import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, forkJoin, map, of } from 'rxjs';
import { environment } from '../../../environments/environment';
import { Student } from './student.service';
import { SchoolDataService } from './school-data.service';

export interface BulletinData {
  student: Student;
  grades: any[];
  allSubjects: string[];
  term: string;
  classAverage: number;
  scientificAverage: number;
  literaryAverage: number;
  sportsAverage: number;
  classRank: number;
  schoolRank: number;
  totalStudents: number;
  teachers: { [subject: string]: string };
  missingGrades: string[];
}

@Injectable({ providedIn: 'root' })
export class BulletinService {
  private apiUrl = environment.apiUrl;

  constructor(
    private http: HttpClient,
    private schoolData: SchoolDataService
  ) {}

  getBulletinData(studentId: number, term: string): Observable<BulletinData> {
    return forkJoin({
      student: this.http.get<Student>(`${this.apiUrl}/students/${studentId}`),
      grades: this.http.get<any[]>(`${this.apiUrl}/grades/student/${studentId}`),
      allStudents: this.http.get<Student[]>(`${this.apiUrl}/students`),
      allGrades: this.http.get<any[]>(`${this.apiUrl}/grades`)
    }).pipe(
      map(({ student, grades, allStudents, allGrades }) => {
        const filteredGrades = term ? grades.filter(g => g.term === term) : grades;

        // Déterminer le niveau de l'étudiant (simplifié)
        let studentLevel = 'Lycée';

        // Récupérer toutes les matières du niveau
        const allSubjects = this.schoolData.subjectsByLevel[studentLevel] || this.schoolData.getAllSubjects();

        // Trouver les matières manquantes
        const gradedSubjects = filteredGrades.map(g => g.subject);
        const missingGrades = allSubjects.filter(sub => !gradedSubjects.includes(sub));

        // Créer un tableau complet avec toutes les matières (0 pour les manquantes)
        const completeGrades = allSubjects.map(subject => {
          const existingGrade = filteredGrades.find(g => g.subject === subject);
          return existingGrade || {
            subject: subject,
            score: 0,
            term: term,
            teacher: null,
            isMissing: true
          };
        });

        // Calcul des moyennes
        const gradedOnly = filteredGrades.length > 0 ? filteredGrades : [];
        const classAverage = gradedOnly.length > 0
          ? gradedOnly.reduce((sum, g) => sum + g.score, 0) / gradedOnly.length
          : 0;

        const scientificSubjects = ['Mathématiques', 'Physique-Chimie', 'Sciences de la vie et de la Terre (SVT)', 'Sciences de l\'ingénieur', 'Informatique', 'Éveil scientifique'];
        const literarySubjects = ['Français', 'Philosophie', 'Histoire-Géographie', 'Anglais', 'Espagnol', 'Allemand', 'Latin', 'Grec', 'Éveil historique et géographique'];
        const sportsSubjects = ['Éducation physique et sportive (EPS)', 'Éducation physique et sportive'];

        const scientificGrades = gradedOnly.filter(g => scientificSubjects.includes(g.subject));
        const literaryGrades = gradedOnly.filter(g => literarySubjects.includes(g.subject));
        const sportsGrades = gradedOnly.filter(g => sportsSubjects.includes(g.subject));

        const scientificAverage = scientificGrades.length > 0
          ? scientificGrades.reduce((sum, g) => sum + g.score, 0) / scientificGrades.length
          : 0;

        const literaryAverage = literaryGrades.length > 0
          ? literaryGrades.reduce((sum, g) => sum + g.score, 0) / literaryGrades.length
          : 0;

        const sportsAverage = sportsGrades.length > 0
          ? sportsGrades.reduce((sum, g) => sum + g.score, 0) / sportsGrades.length
          : 0;

        // Calcul des rangs
        const studentAverages = allStudents.map(s => {
          const studentGrades = allGrades.filter(g => g.studentId === s.id);
          const filtered = term ? studentGrades.filter(g => g.term === term) : studentGrades;
          const avg = filtered.length > 0 ? filtered.reduce((sum, g) => sum + g.score, 0) / filtered.length : 0;
          return { id: s.id, average: avg };
        }).sort((a, b) => b.average - a.average);

        const classRank = studentAverages.findIndex(s => s.id === studentId) + 1;
        const schoolRank = classRank;

        // Noms des professeurs
        const teachers: { [subject: string]: string } = {};
        filteredGrades.forEach(g => {
          if (g.teacher) {
            teachers[g.subject] = `${g.teacher.firstName} ${g.teacher.lastName}`;
          }
        });

        return {
          student,
          grades: completeGrades,
          allSubjects,
          term,
          classAverage,
          scientificAverage,
          literaryAverage,
          sportsAverage,
          classRank,
          schoolRank,
          totalStudents: allStudents.length,
          teachers,
          missingGrades
        };
      })
    );
  }

  // Générer les bulletins pour une liste d'étudiants
  generateBulletinsForStudents(students: Student[], term: string): Observable<BulletinData[]> {
    if (students.length === 0) {
      return of([]);
    }

    const observables = students.map(s => this.getBulletinData(s.id!, term));
    return forkJoin(observables);
  }
}
